+/// Keywords that should never be consumed as implicit aliases because they
+/// begin/continue the next clause in this grammar position.
+fn is_alias_terminator_kw(k: &TokenKind) -> bool {
+    matches!(
+        k,
+        TokenKind::KwCross
+            | TokenKind::KwExcept
+            | TokenKind::KwFull
+            | TokenKind::KwGroup
+            | TokenKind::KwHaving
+            | TokenKind::KwInner
+            | TokenKind::KwIntersect
+            | TokenKind::KwJoin
+            | TokenKind::KwLeft
+            | TokenKind::KwLimit
+            | TokenKind::KwNatural
+            | TokenKind::KwOffset
+            | TokenKind::KwOn
+            | TokenKind::KwOrder
+            | TokenKind::KwOuter
+            | TokenKind::KwReturning
+            | TokenKind::KwRight
+            | TokenKind::KwUnion
+            | TokenKind::KwUsing
+            | TokenKind::KwWhere
+            | TokenKind::KwWindow
+    )
+}
